var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>안내드립니다. 부상장병의 가족 여러분은 B동 프론트 데스크를 방문해 주시기 바랍니다.</color>","JPN":"<color=#ffd34c>ご案内いたします。負傷兵のご家族の皆さまは、B棟のフロントデスクまでお越しください。</color>","ENG":"<color=#ffd34c>Attention please. Families of wounded soldiers should go to Building B's front desk.</color>","TWN":"<color=#ffd34c>醫院通知，請傷者的家人移動至櫃台。</color>"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>173차 응급 환자 도착했습니다. 대기 인원들은 전원 응급실로…….</color>","JPN":"<color=#ffd34c>173次の救急患者が到着しました。待機中のスタッフは全員救急処置室へ……</color>","ENG":"<color=#ffd34c>The 173rd emergency patients have arrived. All personnel to the emergency room...</color>","TWN":"<color=#ffd34c>第173波急救患者已抵達，請相關人員移動至急診室……</color>"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"어디보자……. 202호, 202호…….","JPN":"えーと……202号室、202号室……","ENG":"Let’s see here... Room 202... 202...","TWN":"我看看喔……202號，202號……"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"아, 이 병실 맞아?","JPN":"あ、この病室で合ってるかな？","ENG":"Are you sure this is the right place?","TWN":"是這間病房嗎？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"그래. 여기가 맞다.","JPN":"ああ、ここみたいだ。","ENG":"Yes. I’m sure.","TWN":"沒錯，就是這間。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"큰 오빠한테 애가 있었다니 의외네……. 장례식 치를 때도 몰랐는데.","JPN":"兄さんに子どもがいたなんて意外ね……\\n葬式の時にも来なかったみたいだし。","ENG":"I didn’t know big brother had a kid... I wasn’t even aware of it during the funeral.","TWN":"沒想到大哥竟然有孩子……之前在葬禮上也沒聽說。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"아버지가 예전에 큰 오빠네는 불임 판정 받았다고 하지 않았어?","JPN":"父さんが以前、兄さんのところは不妊だって言ってなかったっけ？","ENG":"Didn't Father say something about him being sterile?","TWN":"爸之前不是說大哥是不孕症嗎？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"그 인간 말을 곧이곧대로 믿지 마라. 그러니 아랫사람들에게 호구 소리 듣지.","JPN":"あの人が言ったことを素直に信じるな。だから目下の人間にも舐められるんだ。","ENG":"Don’t trust what that old geezer says. That’s why people call you gullible.","TWN":"那個人說的話你不用當真，你就是這樣才會被底下的人耍。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"신경 꺼. 내 일이거든.","JPN":"別にいいでしょ。余計なお世話よ。","ENG":"Whatever. That’s my business, not yours.","TWN":"不用你管，這不關你的事！"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"흥. 뭐, 모르지. 아버지가 또 어디 첩에게서 덜컥 낳고 떠맡긴 걸지도.","JPN":"フン。まあ、親父がどっかの妾に産ませて、押し付けられたのかもな。","ENG":"Hmph. Who knows? Maybe Father got himself another wife and had another child with her.","TWN":"哼，誰知道，說不定是爸又跟哪個小三生的，然後叫大哥幫他養。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"내 앞에서 그딴 소리가 나와? 저질이야, 진짜.","JPN":"私の前でそんなこと言うわけ？　最低よ、本当に。","ENG":"You’re seriously saying that to my face? Unbelievable.","TWN":"你在我面前提什麼小三？有夠低級的！"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"저질이기로는 너만 하겠냐. 체스 도박 한 판에 건물 한 채씩 날려 먹는 주제에.","JPN":"最低なのはお前だろう。賭けチェスに興じるたびに、ビルを一棟吹っ飛ばすくせに。","ENG":"Not as much as you. You’re the one who lost an entire house on one chess gambling match.","TWN":"你以為只有你能低級嗎？是誰賭一局西洋棋，就把一棟房子輸掉的？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"아무리 생각해도 형님은 널 너무 오냐오냐 받아 줬어.","JPN":"どう考えても兄貴はお前に甘すぎだった。","ENG":"He’s always had a soft spot for you, for some reason...","TWN":"我看大哥就是太寵你了啦！"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"내 욕은 해도 큰 오빠 욕은 하지 마. 다음에 이겨서 두 채로 받으면 되는 걸 가지고.","JPN":"私のことはいいけど、兄さんのことは悪く言わないでよ。\\n次の賭けで勝って、二棟分取り返せばいいでしょ。","ENG":"Talk trash about me all you want, but not to my big brother. Plus, I’ll double down and recover my losses next time.","TWN":"喂，你罵我就好，不要扯到大哥身上！我下次贏兩棟房子回來不就好了！"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"……오빠, 막 입국해서 그러는데 큰 오빠네는 연구소 사고로 죽은 거 아니었어?","JPN":"……こっちに来たばかりでまだ状況がわからないけど、\\n兄さん一家って研究所の事故で死んだんじゃなかったっけ。","ENG":"Um...I just came back from overseas so... I thought his family died because of a lab accident?","TWN":"……哥，我才剛回來不久不是很清楚，大哥一家不是在研究室意外中喪生了嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"그래. 요즘 같은 난리통에도 대문짝만 하게 보도됐지.","JPN":"ああ、事件ばかりのこんなご時世でも、大々的に報道されたな。","ENG":"Yes. That’s how it was reported on the front page of the newspapers.","TWN":"沒錯，雖然最近世道很亂，但媒體還是有大篇幅的報導。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"그런데 쟤는 왜 상처 하나 없이 멀쩡한 건데?","JPN":"なのに、なんであの子は傷ひとつないの？","ENG":"But I don’t see any signs of trauma anywhere on her.","TWN":"那她為什麼毫髮無傷？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"궁금하면 직접 물어 봐. 난 관심없다.","JPN":"気になるなら自分で聞けよ。俺は興味ないから。","ENG":"Go ask about it yourself, if you’re that curious. I don’t care.","TWN":"想知道你自己問她吧，我沒興趣知道。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};